{
  "title": "उद्धरणों को एस्केप करना",
  "group": "वार्मअप: एस्केपिंग",
  "options": [
    {
      "text": "echo 'It's 🔨 Time!'"
    },
    {
      "text": "echo 'It\\\\'s 🔨 Time!'"
    },
    {
      "text": "echo 'It'\\\\''s 🔨 Time!'"
    },
    {
      "text": "echo 'It''s 🔨 Time!'"
    },
    {
      "text": "Error"
    }
  ],
  "questionProse": [
    "_क्या प्रिंट करेगा `It's 🔨 Time!`?_"
  ],
  "explanationProse": [
    "मुझे पता है। यह जंगली है कि कितनी जल्दी एस्केपिंग स्ट्रिंग्स को पार्स करना मुश्किल बना देती है। Bash स्ट्रिंग्स में अन्य भाषाओं को एस्केप करने की कल्पना करें - उन सभी कोट्स, एपॉस्ट्रॉफी और `$` प्रतीकों के साथ जो आपको गड़बड़ कर देते हैं। 🫠\n\n    सिंगल कोट्स को सिंगल-कोटेड स्ट्रिंग्स के अंदर एस्केप करने की आवश्यकता होती है। क्लोज़-कोट, एस्केप्ड-कोट, रीओपन-कोट अनुक्रम (`'\\''`) आउटपुट की अनुमति देता है:",
    "इसे संभालने के अन्य तरीके भी हैं, लेकिन यह सबसे सामान्य है।"
  ]
}
